import React, { Suspense, lazy, useState } from 'react';
import * as Tabs from '@radix-ui/react-tabs';
import { SkeletonTablePage } from '../components/SkeletonUI';
import s from './StrategyLabPage.module.css';

const BotBuilderPage = lazy(() => import('./BotBuilderPage'));
const BacktestDashboardPage = lazy(() => import('./BacktestDashboardPage'));
const BacktestResultsPage = lazy(() => import('./BacktestResultsPage'));
const BacktestRunnerPage = lazy(() => import('./BacktestRunnerPage'));

const TAB_ITEMS = [
  { value: 'builder',   label: 'Builder' },
  { value: 'dashboard', label: 'Dashboard' },
  { value: 'results',   label: 'Results' },
  { value: 'runner',    label: 'Runner' },
];

function LoadingFallback() {
  return (
    <SkeletonTablePage title="Strategy Lab" metricCount={3} cols={6} rows={6} />
  );
}

export default function StrategyLabPage() {
  const [activeTab, setActiveTab] = useState('builder');

  return (
    <div className={s.page}>
      <Tabs.Root value={activeTab} onValueChange={setActiveTab}>
        <Tabs.List className={s.tabList}>
          {TAB_ITEMS.map((tab) => (
            <Tabs.Trigger
              key={tab.value}
              value={tab.value}
              className={`${s.tabTrigger} ${activeTab === tab.value ? s.tabTriggerActive : ''}`}
            >
              {tab.label}
            </Tabs.Trigger>
          ))}
        </Tabs.List>

        <Tabs.Content value="builder" className={s.tabContent}>
          <Suspense fallback={<LoadingFallback />}>
            <BotBuilderPage />
          </Suspense>
        </Tabs.Content>

        <Tabs.Content value="dashboard" className={s.tabContent}>
          <Suspense fallback={<LoadingFallback />}>
            <BacktestDashboardPage />
          </Suspense>
        </Tabs.Content>

        <Tabs.Content value="results" className={s.tabContent}>
          <Suspense fallback={<LoadingFallback />}>
            <BacktestResultsPage />
          </Suspense>
        </Tabs.Content>

        <Tabs.Content value="runner" className={s.tabContent}>
          <Suspense fallback={<LoadingFallback />}>
            <BacktestRunnerPage />
          </Suspense>
        </Tabs.Content>
      </Tabs.Root>
    </div>
  );
}
